const problemsData = require('../../data/problems.json');

/**
 * Normalize tags to lowercase trimmed strings
 * @param {string[]} tags
 * @returns {string[]}
 */
function normalizeTags(tags) {
  return tags.map(t => t.trim().toLowerCase()).filter(t => t.length > 0);
}

/**
 * Filter problems by difficulty, limit, and skill tags
 * @param {Object} options
 * @param {string|string[]} [options.tags] - skill tags filter (case-insensitive, comma-separated string or array)
 * @param {string} [options.difficulty] - difficulty filter
 * @param {number} [options.limit] - max number of problems to return
 * @returns {Object} { problems: Array, metadata: Object }
 */
function getProblems({ tags, difficulty, limit } = {}) {
  let tagFilters = [];

  if (tags) {
    if (Array.isArray(tags)) {
      tagFilters = normalizeTags(tags);
    } else if (typeof tags === 'string') {
      tagFilters = normalizeTags(tags.split(','));
    }
  }

  // Filter problems by difficulty if provided
  let filtered = problemsData;
  if (difficulty) {
    filtered = filtered.filter(p => p.difficulty === difficulty);
  }

  // Filter by tags if provided
  if (tagFilters.length > 0) {
    filtered = filtered.filter(p => {
      if (!p.tags || !Array.isArray(p.tags)) return false;
      const problemTags = p.tags.map(t => t.toLowerCase());
      // Problem must have all tags in tagFilters
      return tagFilters.every(tf => problemTags.includes(tf));
    });
  }

  // Stable sort by id ascending
  filtered = _.sortBy(filtered, ['id']);

  // Apply limit if provided
  if (limit && Number.isInteger(limit)) {
    filtered = filtered.slice(0, limit);
  }

  // Metadata includes normalized tags filter
  const metadata = {
    tags: tagFilters,
    difficulty: difficulty || null,
    limit: limit || null,
    totalCount: filtered.length
  };

  return { problems: filtered, metadata };
}

module.exports = {
  getProblems
};
